# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <cmath>
#include <chrono>
#include <random>
#include <map>

std::chrono::steady_clock::time_point start_time;
int N, D, Q;
int queries_used = 0;
std::mt19937 rng;

char do_query(const std::vector<int>& L, const std::vector<int>& R) {
    queries_used++;
    std::cout << L.size() << " " << R.size();
    for (int x : L) std::cout << " " << x;
    for (int x : R) std::cout << " " << x;
    std::cout << std::endl;
    char c;
    std::cin >> c;
    return c;
}

std::map<std::pair<int,int>, char> cache_1v1;

char compare_items(int a, int b) {
    if (a == b) return '=';
    auto key = std::make_pair(std::min(a,b), std::max(a,b));
    auto it = cache_1v1.find(key);
    if (it != cache_1v1.end()) {
        char r = it->second;
        return (a == key.first) ? r : (r == '<' ? '>' : (r == '>' ? '<' : '='));
    }
    if (queries_used >= Q) return '=';
    char r = do_query({a}, {b});
    char stored = (a == key.first) ? r : (r == '<' ? '>' : (r == '>' ? '<' : '='));
    cache_1v1[key] = stored;
    return r;
}

void merge_sort_merge(std::vector<int>& arr, int l, int m, int r) {
    std::vector<int> L(arr.begin()+l, arr.begin()+m+1);
    std::vector<int> R(arr.begin()+m+1, arr.begin()+r+1);
    int i=0, j=0, k=l;
    while (i < (int)L.size() && j < (int)R.size()) {
        if (queries_used >= Q) { arr[k++] = L[i++]; continue; }
        char c = compare_items(L[i], R[j]);
        if (c == '<' || c == '=') arr[k++] = L[i++];
        else arr[k++] = R[j++];
    }
    while (i < (int)L.size()) arr[k++] = L[i++];
    while (j < (int)R.size()) arr[k++] = R[j++];
}

void merge_sort(std::vector<int>& arr, int l, int r) {
    if (l >= r) return;
    int m = l + (r-l)/2;
    merge_sort(arr, l, m);
    merge_sort(arr, m+1, r);
    merge_sort_merge(arr, l, m, r);
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    start_time = std::chrono::steady_clock::now();
    rng.seed(std::chrono::steady_clock::now().time_since_epoch().count());

    std::cin >> N >> D >> Q;

    // Budget: reserve queries for group comparison refinement
    int sort_cost_full = (int)(N * std::ceil(std::log2(std::max(2, N))));
    // Reserve 40% of budget for refinement since direct comparisons are very valuable
    int refinement_reserve = Q * 2 / 5;
    if (sort_cost_full + refinement_reserve > Q) {
        refinement_reserve = std::max(0, Q - sort_cost_full);
    }
    int sort_budget = Q - refinement_reserve;

    // Phase 1: Sort items
    std::vector<int> sorted_items(N);
    std::iota(sorted_items.begin(), sorted_items.end(), 0);
    std::shuffle(sorted_items.begin(), sorted_items.end(), rng);

    if (sort_cost_full <= sort_budget) {
        merge_sort(sorted_items, 0, N-1);
    } else {
        // Partial: sort pivots, binary search rest
        int k = N;
        while (k > 2) {
            int cost = (int)(k * std::ceil(std::log2(std::max(2, k))));
            int bs_cost = (N - k) * (int)std::ceil(std::log2(std::max(2, k)));
            if (cost + bs_cost <= sort_budget) break;
            k--;
        }
        k = std::max(2, k);

        std::vector<int> pivots(sorted_items.begin(), sorted_items.begin() + k);
        std::vector<int> non_pivots(sorted_items.begin() + k, sorted_items.end());

        merge_sort(pivots, 0, k-1);

        struct RankedItem { double pos; int item; };
        std::vector<RankedItem> all_ranked;
        for (int i = 0; i < k; i++) all_ranked.push_back({(double)i * 2, pivots[i]});

        for (int item : non_pivots) {
            int lo = 0, hi = k - 1, insert_pos = k;
            while (lo <= hi && queries_used < sort_budget) {
                int mid = (lo + hi) / 2;
                char c = compare_items(item, pivots[mid]);
                if (c == '<') { insert_pos = mid; hi = mid - 1; }
                else if (c == '>') { lo = mid + 1; }
                else { insert_pos = mid; break; }
            }
            double pos;
            if (insert_pos == 0) pos = -1.0;
            else if (insert_pos >= k) pos = k * 2.0 + 1;
            else pos = insert_pos * 2.0 - 1.0;
            all_ranked.push_back({pos, item});
        }

        std::sort(all_ranked.begin(), all_ranked.end(), [](const RankedItem& a, const RankedItem& b) { return a.pos < b.pos; });
        sorted_items.clear();
        for (auto& r : all_ranked) sorted_items.push_back(r.item);
    }

    // Phase 2: Snake/zigzag assignment from sorted order
    // sorted_items[0] is lightest, sorted_items[N-1] is heaviest
    // Deal: sorted from heavy to light in snake pattern
    std::vector<int> assignment(N, 0);
    std::vector<std::vector<int>> group_items(D);

    // Reverse so heaviest first
    std::vector<int> heavy_first(sorted_items.rbegin(), sorted_items.rend());
    int idx = 0;
    int direction = 1;
    int g = 0;
    for (int item : heavy_first) {
        assignment[item] = g;
        group_items[g].push_back(item);
        g += direction;
        if (g >= D) { g = D - 1; direction = -1; }
        else if (g < 0) { g = 0; direction = 1; }
    }

    // Phase 3: Direct group comparison refinement
    // Use remaining queries to find heaviest/lightest groups and balance them
    int refinement_queries = Q - queries_used;

    // Each round: tournament to find heaviest (D-1 queries), lightest (D-2 queries),
    // verify (1 query), binary search for item to move (log2(group_size) queries)
    // Total per round: ~2D + log2(N/D)

    auto compare_groups = [&](int g1, int g2) -> char {
        if (group_items[g1].empty() || group_items[g2].empty()) return '=';
        if (queries_used >= Q) return '=';
        return do_query(group_items[g1], group_items[g2]);
    };

    int stale = 0;
    while (queries_used < Q - 1 && stale < 6) {
        // Need at least 2*(D-1) + some queries for a meaningful round
        if (Q - queries_used < 2 * D + 2) break;

        // Find heaviest group via tournament
        int heavy = 0;
        for (int g = 1; g < D && queries_used < Q; g++) {
            char r = compare_groups(heavy, g);
            if (r == '<') heavy = g;
        }

        // Find lightest group via tournament (exclude heavy in comparison logic)
        int light = -1;
        for (int g = 0; g < D; g++) {
            if (g == heavy) continue;
            if (light == -1) { light = g; continue; }
            if (queries_used >= Q) break;
            char r = compare_groups(light, g);
            if (r == '>') light = g;
        }
        if (light == -1 || light == heavy) break;

        // Verify heavy > light
        if (queries_used >= Q) break;
        char verify = compare_groups(heavy, light);
        if (verify != '>') {
            if (verify == '=') { stale++; continue; }
            // verify == '<' means light is heavier, shouldn't happen but handle
            std::swap(heavy, light);
        }

        // Binary search for item to move from heavy to light
        std::vector<int>& h_items = group_items[heavy];
        std::vector<int>& l_items = group_items[light];

        if (h_items.size() <= 1) { stale++; continue; }

        // Sort heavy group items using their position in the sorted order
        // Create a rank map
        std::vector<int> rank_map(N, 0);
        for (int i = 0; i < N; i++) rank_map[sorted_items[i]] = i;
        std::sort(h_items.begin(), h_items.end(), [&](int a, int b) {
            return rank_map[a] < rank_map[b];
        });

        // Binary search: find item x such that (heavy-{x}) and (light+{x}) are balanced
        int lo = 0, hi = (int)h_items.size() - 1;
        int best_idx = -1;

        while (lo <= hi && queries_used < Q) {
            int mid = (lo + hi) / 2;
            int candidate = h_items[mid];

            std::vector<int> new_heavy, new_light;
            for (int x : h_items) if (x != candidate) new_heavy.push_back(x);
            new_light = l_items;
            new_light.push_back(candidate);

            if (new_heavy.empty()) { lo = mid + 1; continue; }

            char r = do_query(new_heavy, new_light);

            if (r == '=') {
                best_idx = mid;
                break;
            } else if (r == '>') {
                best_idx = mid; // valid but can do better
                lo = mid + 1;
            } else {
                hi = mid - 1;
            }
        }

        if (best_idx >= 0 && best_idx < (int)h_items.size()) {
            int item_to_move = h_items[best_idx];
            assignment[item_to_move] = light;
            h_items.erase(h_items.begin() + best_idx);
            l_items.push_back(item_to_move);
            stale = 0;
        } else {
            stale++;
        }
    }

    // Exhaust remaining queries
    while (queries_used < Q) {
        do_query({0}, {(N > 1) ? 1 : 0});
    }

    // Output
    for (int i = 0; i < N; i++) std::cout << assignment[i] << (i == N-1 ? "\n" : " ");
    return 0;
}
