# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <cmath>
#include <chrono>
#include <random>
#include <map>

int N, D, Q;
int queries_used = 0;
std::mt19937 rng;

char do_query(const std::vector<int>& L, const std::vector<int>& R) {
    queries_used++;
    std::cout << L.size() << " " << R.size();
    for (int x : L) std::cout << " " << x;
    for (int x : R) std::cout << " " << x;
    std::cout << std::endl;
    char c;
    std::cin >> c;
    return c;
}

std::map<std::pair<int,int>, char> cache_1v1;

char compare_items(int a, int b) {
    if (a == b) return '=';
    auto key = std::make_pair(std::min(a,b), std::max(a,b));
    auto it = cache_1v1.find(key);
    if (it != cache_1v1.end()) {
        char r = it->second;
        return (a == key.first) ? r : (r == '<' ? '>' : (r == '>' ? '<' : '='));
    }
    if (queries_used >= Q) return '=';
    char r = do_query({a}, {b});
    char stored = (a == key.first) ? r : (r == '<' ? '>' : (r == '>' ? '<' : '='));
    cache_1v1[key] = stored;
    return r;
}

void merge_sort_merge(std::vector<int>& arr, int l, int m, int r, int budget) {
    std::vector<int> L(arr.begin()+l, arr.begin()+m+1);
    std::vector<int> R(arr.begin()+m+1, arr.begin()+r+1);
    int i=0, j=0, k=l;
    while (i < (int)L.size() && j < (int)R.size()) {
        if (queries_used >= budget) { arr[k++] = L[i++]; continue; }
        char c = compare_items(L[i], R[j]);
        if (c == '<' || c == '=') arr[k++] = L[i++];
        else arr[k++] = R[j++];
    }
    while (i < (int)L.size()) arr[k++] = L[i++];
    while (j < (int)R.size()) arr[k++] = R[j++];
}

void merge_sort(std::vector<int>& arr, int l, int r, int budget) {
    if (l >= r) return;
    if (queries_used >= budget) return;
    int m = l + (r-l)/2;
    merge_sort(arr, l, m, budget);
    merge_sort(arr, m+1, r, budget);
    merge_sort_merge(arr, l, m, r, budget);
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    rng.seed(42);

    std::cin >> N >> D >> Q;

    // Budget: sort needs N*log2(N), rest for refinement
    int sort_cost_full = (int)(N * std::ceil(std::log2(std::max(2, N))));
    // Use exactly what's needed for sort (up to 50%), rest for refinement
    int sort_budget = std::min(sort_cost_full, (int)(Q * 0.5));

    // Phase 1: Sort items
    std::vector<int> sorted_items(N);
    std::iota(sorted_items.begin(), sorted_items.end(), 0);
    std::shuffle(sorted_items.begin(), sorted_items.end(), rng);

    if (sort_cost_full <= sort_budget) {
        merge_sort(sorted_items, 0, N-1, sort_budget);
    } else {
        // Partial: sort pivots, binary search rest
        int k = N;
        while (k > 2) {
            int cost = (int)(k * std::ceil(std::log2(std::max(2, k))));
            int bs_cost = (N - k) * (int)std::ceil(std::log2(std::max(2, k)));
            if (cost + bs_cost <= sort_budget) break;
            k--;
        }
        k = std::max(2, k);

        std::vector<int> pivots(sorted_items.begin(), sorted_items.begin() + k);
        std::vector<int> non_pivots(sorted_items.begin() + k, sorted_items.end());

        merge_sort(pivots, 0, k-1, sort_budget);

        struct RankedItem { double pos; int item; };
        std::vector<RankedItem> all_ranked;
        for (int i = 0; i < k; i++) all_ranked.push_back({(double)i * 2, pivots[i]});

        for (int item : non_pivots) {
            int lo = 0, hi = k - 1, insert_pos = k;
            while (lo <= hi && queries_used < sort_budget) {
                int mid = (lo + hi) / 2;
                char c = compare_items(item, pivots[mid]);
                if (c == '<') { insert_pos = mid; hi = mid - 1; }
                else if (c == '>') { lo = mid + 1; }
                else { insert_pos = mid; break; }
            }
            double pos;
            if (insert_pos == 0) pos = -1.0;
            else if (insert_pos >= k) pos = k * 2.0 + 1;
            else pos = insert_pos * 2.0 - 1.0;
            all_ranked.push_back({pos, item});
        }

        std::sort(all_ranked.begin(), all_ranked.end(), [](const RankedItem& a, const RankedItem& b) { return a.pos < b.pos; });
        sorted_items.clear();
        for (auto& r : all_ranked) sorted_items.push_back(r.item);
    }

    // Build rank map
    std::vector<int> rank_map(N, 0);
    for (int i = 0; i < N; i++) rank_map[sorted_items[i]] = i;

    // Phase 2: Snake/zigzag assignment (heaviest first)
    std::vector<int> assignment(N, 0);
    std::vector<std::vector<int>> group_items(D);

    std::vector<int> heavy_first(sorted_items.rbegin(), sorted_items.rend());
    int direction = 1;
    int g = 0;
    for (int item : heavy_first) {
        assignment[item] = g;
        group_items[g].push_back(item);
        g += direction;
        if (g >= D) { g = D - 1; direction = -1; }
        else if (g < 0) { g = 0; direction = 1; }
    }

    // Sort items within each group by rank
    for (int gi = 0; gi < D; gi++) {
        std::sort(group_items[gi].begin(), group_items[gi].end(), [&](int a, int b) {
            return rank_map[a] < rank_map[b];
        });
    }

    // Phase 3: Refinement - cycle through ALL pairs, fix each imbalance with a move
    // This avoids expensive full tournament (2*D queries) and instead does
    // targeted 1-query comparisons + log2 binary search moves.

    auto compare_groups = [&](int g1, int g2) -> char {
        if (group_items[g1].empty() || group_items[g2].empty()) return '=';
        if (queries_used >= Q) return '=';
        return do_query(group_items[g1], group_items[g2]);
    };

    // Strategy: multiple passes over all pairs
    // Each pass: for each pair (i,j), compare groups. If imbalanced, binary search for best move.
    // A move from heavy to light reduces the imbalance of this pair.
    // Unlike tournament which only fixes the MOST extreme pair, this fixes ALL pairs.

    std::vector<std::pair<int,int>> pairs;
    for (int i = 0; i < D; i++)
        for (int j = i+1; j < D; j++)
            pairs.push_back({i, j});

    int consecutive_no_improve = 0;
    int max_no_improve = 4; // full passes with no improvement

    while (queries_used < Q && consecutive_no_improve < max_no_improve) {
        std::shuffle(pairs.begin(), pairs.end(), rng);
        bool improved_this_pass = false;

        for (auto& [gi, gj] : pairs) {
            // Need at least ~log2(N/D)+1 queries for this pair
            int needed = 1 + (int)std::ceil(std::log2(std::max(2, N/D)));
            if (Q - queries_used < needed) break;

            char cmp = compare_groups(gi, gj);
            if (cmp == '=') continue;

            int heavy_g = (cmp == '>') ? gi : gj;
            int light_g = (cmp == '>') ? gj : gi;

            std::vector<int>& h_items = group_items[heavy_g];
            std::vector<int>& l_items = group_items[light_g];

            if (h_items.size() <= 1) continue;

            // Binary search for item to move from heavy to light
            int lo = 0, hi = (int)h_items.size() - 1;
            int best_idx = -1;

            while (lo <= hi && queries_used < Q) {
                int mid = (lo + hi) / 2;
                int candidate = h_items[mid];

                std::vector<int> new_heavy, new_light;
                for (int x : h_items) if (x != candidate) new_heavy.push_back(x);
                new_light = l_items;
                new_light.push_back(candidate);

                if (new_heavy.empty()) { lo = mid + 1; continue; }

                char r = do_query(new_heavy, new_light);

                if (r == '=') {
                    best_idx = mid;
                    break;
                } else if (r == '>') {
                    best_idx = mid; // valid, heavy still > light after move
                    lo = mid + 1;   // try heavier item
                } else {
                    hi = mid - 1;   // too heavy to move
                }
            }

            if (best_idx >= 0 && best_idx < (int)h_items.size()) {
                int item_to_move = h_items[best_idx];
                assignment[item_to_move] = light_g;
                h_items.erase(h_items.begin() + best_idx);
                l_items.push_back(item_to_move);
                std::sort(l_items.begin(), l_items.end(), [&](int a, int b) {
                    return rank_map[a] < rank_map[b];
                });
                improved_this_pass = true;
            }
        }

        if (!improved_this_pass) {
            consecutive_no_improve++;
        } else {
            consecutive_no_improve = 0;
        }
    }

    // Exhaust remaining queries
    while (queries_used < Q) {
        do_query({0}, {(N > 1) ? 1 : 0});
    }

    // Output
    for (int i = 0; i < N; i++) std::cout << assignment[i] << (i == N-1 ? "\n" : " ");
    return 0;
}
